import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { authAPI } from '../services/api';
import { useToast } from '../context/ToastContext';
import Logo from '../components/Logo';
import './Auth.css';

const STEPS = { EMAIL: 'email', RESET: 'reset', DONE: 'done' };

export default function ForgotPassword() {
  const [step, setStep]   = useState(STEPS.EMAIL);
  const [email, setEmail] = useState('');
  const [form, setForm]   = useState({ otp: '', newPassword: '' });
  const [loading, setLoading] = useState(false);
  const toast    = useToast();
  const navigate = useNavigate();

  const handleSendOtp = async (e) => {
    e.preventDefault();
    if (!email) { toast.error('Enter your email'); return; }
    setLoading(true);
    try {
      await authAPI.forgotPassword(email);
      toast.success('OTP sent to your email');
      setStep(STEPS.RESET);
    } catch (err) {
      const msg = err.response?.data;
      toast.error(typeof msg === 'string' ? msg : 'Email not found');
    } finally {
      setLoading(false);
    }
  };

  const handleReset = async (e) => {
    e.preventDefault();
    if (!form.otp || !form.newPassword) { toast.error('Fill in all fields'); return; }
    setLoading(true);
    try {
      await authAPI.resetPassword({ email, ...form });
      toast.success('Password reset successful!');
      setStep(STEPS.DONE);
    } catch (err) {
      const msg = err.response?.data;
      toast.error(typeof msg === 'string' ? msg : 'Reset failed. Check OTP and try again.');
    } finally {
      setLoading(false);
    }
  };

  if (step === STEPS.DONE) {
    return (
      <div className="auth-page">
        <div className="auth-container fade-up" style={{ textAlign: 'center' }}>
          <div style={{ fontSize: 56, marginBottom: 'var(--gap-lg)' }}>✅</div>
          <h2>Password Reset!</h2>
          <p className="text-dim" style={{ marginTop: 8 }}>
            Your password has been updated successfully.
          </p>
          <Link to="/login" className="btn btn-gold" style={{ marginTop: 'var(--gap-xl)', display: 'inline-flex' }}>
            Go to Login →
          </Link>
        </div>
      </div>
    );
  }

  if (step === STEPS.RESET) {
    return (
      <div className="auth-page">
        <div className="auth-decoration" />
        <div className="auth-container fade-up">
          <div className="auth-header">
            <Link to="/" className="auth-logo">
              <Logo size={24} style={{ marginRight: 8, display: 'inline-block', verticalAlign: 'middle' }} />
              Book<em>Nest</em>
            </Link>
            <h1>Reset Password</h1>
            <p className="text-dim">Enter the OTP sent to <strong style={{ color: 'var(--gold)' }}>{email}</strong></p>
          </div>

          <form className="auth-form" onSubmit={handleReset}>
            <div className="form-group">
              <label>OTP Code</label>
              <input
                type="text"
                placeholder="Enter 6-digit OTP"
                value={form.otp}
                onChange={e => setForm({ ...form, otp: e.target.value })}
                maxLength={6}
              />
            </div>

            <div className="form-group">
              <label>New Password</label>
              <input
                type="password"
                placeholder="New secure password"
                value={form.newPassword}
                onChange={e => setForm({ ...form, newPassword: e.target.value })}
              />
              <span className="password-hint">
                Must contain uppercase, lowercase, number, and special character
              </span>
            </div>

            <button type="submit" className="btn btn-gold auth-submit" disabled={loading}>
              {loading ? 'Resetting...' : 'Reset Password'}
            </button>
          </form>

          <div className="resend-row" style={{ marginTop: 'var(--gap-lg)' }}>
            <span>Didn't receive OTP?</span>
            <button
              className="btn btn-ghost"
              style={{ padding: '4px 12px', fontSize: 13 }}
              onClick={async () => {
                try { await authAPI.forgotPassword(email); toast.info('OTP resent'); }
                catch { toast.error('Failed to resend'); }
              }}
            >
              Resend
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="auth-page">
      <div className="auth-decoration" />
      <div className="auth-container fade-up">
        <div className="auth-header">
          <Link to="/" className="auth-logo">
            <Logo size={24} style={{ marginRight: 8, display: 'inline-block', verticalAlign: 'middle' }} />
            Book<em>Nest</em>
          </Link>
          <h1>Forgot Password?</h1>
          <p className="text-dim">Enter your email and we'll send you a reset OTP</p>
        </div>

        <form className="auth-form" onSubmit={handleSendOtp}>
          <div className="form-group">
            <label>Email Address</label>
            <input
              type="email"
              placeholder="you@example.com"
              value={email}
              onChange={e => setEmail(e.target.value)}
            />
          </div>

          <button type="submit" className="btn btn-gold auth-submit" disabled={loading}>
            {loading ? 'Sending OTP...' : 'Send Reset OTP'}
          </button>
        </form>

        <div className="auth-footer">
          <p className="text-dim text-sm">
            Remember it? <Link to="/login">Back to login</Link>
          </p>
        </div>
      </div>
    </div>
  );
}
